import websockets
from websockets.server import WebSocketServerProtocol

logging.basicConfig(level=logging.INFO)


def now_ms() -> int:
    return int(time.time() * 1000)


def jdump(obj: Any) -> str:
    return json.dumps(obj, separators=(",", ":"), ensure_ascii=False)


@dataclass
class Item:
    item_id: str
    template: str
    meta: dict = field(default_factory=dict)


@dataclass
class Player:
    player_id: str
    name: str
    ws: WebSocketServerProtocol
    inventory: Set[str] = field(default_factory=set)
    lock: asyncio.Lock = field(default_factory=asyncio.Lock)
    connected_at_ms: int = field(default_factory=now_ms)


class GameState:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.ws_to_pid: Dict[WebSocketServerProtocol, str] = {}
        self.items: Dict[str, Item] = {}
        self.item_owner: Dict[str, str] = {}  # item_id -> player_id
        self._global_lock = asyncio.Lock()
        self._transfer_nonce_seen: Dict[Tuple[str, str], int] = {}  # (player_id, nonce) -> ms
        self._nonce_lock = asyncio.Lock()

    async def register(self, ws: WebSocketServerProtocol, player_id: str, name: str) -> Player:
        async with self._global_lock:
            if player_id in self.players:
                old = self.players[player_id]
                try:
                    await old.ws.close(code=4000, reason="Logged in elsewhere")
                except Exception:
                    pass
                self.ws_to_pid.pop(old.ws, None)
            p = Player(player_id=player_id, name=name, ws=ws)
            self.players[player_id] = p
            self.ws_to_pid[ws] = player_id
            return p

    async def unregister(self, ws: WebSocketServerProtocol):
        async with self._global_lock:
            pid = self.ws_to_pid.pop(ws, None)
            if not pid:
                return
            p = self.players.get(pid)
            if p and p.ws is ws:
                self.players.pop(pid, None)

    def get_player_by_ws(self, ws: WebSocketServerProtocol) -> Optional[Player]:
        pid = self.ws_to_pid.get(ws)
        if not pid:
            return None
        return self.players.get(pid)

    async def ensure_nonce_once(self, player_id: str, nonce: str, ttl_ms: int = 5 * 60 * 1000) -> bool:
        t = now_ms()
        async with self._nonce_lock:
            # cleanup occasionally
            if len(self._transfer_nonce_seen) > 10000:
                cutoff = t - ttl_ms
                for k, ts in list(self._transfer_nonce_seen.items()):
                    if ts < cutoff:
                        self._transfer_nonce_seen.pop(k, None)
            key = (player_id, nonce)
            if key in self._transfer_nonce_seen and (t - self._transfer_nonce_seen[key]) < ttl_ms:
                return False
            self._transfer_nonce_seen[key] = t
            return True

    async def create_item(self, owner_id: str, template: str, meta: Optional[dict] = None) -> Item:
        meta = meta or {}
        item_id = secrets.token_urlsafe(12)
        item = Item(item_id=item_id, template=template, meta=meta)
        async with self._global_lock:
            self.items[item_id] = item
            self.item_owner[item_id] = owner_id
            p = self.players.get(owner_id)
            if p:
                async with p.lock:
                    p.inventory.add(item_id)
        return item

    async def snapshot_inventory(self, player_id: str) -> dict:
        p = self.players.get(player_id)
        if not p:
            return {"items": []}
        async with p.lock:
            item_ids = list(p.inventory)
        items = []
        for iid in item_ids:
            it = self.items.get(iid)
            if it:
                items.append({"item_id": it.item_id, "template": it.template, "meta": it.meta})
        return {"items": items}

    async def transfer_item(self, from_id: str, to_id: str, item_id: str) -> Tuple[bool, str]:
        if from_id == to_id:
            return False, "cannot_transfer_to_self"
        from_p = self.players.get(from_id)
        to_p = self.players.get(to_id)
        if not from_p or not to_p:
            return False, "player_not_found"
        if item_id not in self.items:
            return False, "item_not_found"

        # lock ordering to avoid deadlocks
        first, second = (from_p, to_p) if from_id < to_id else (to_p, from_p)
        async with first.lock:
            async with second.lock:
                owner = self.item_owner.get(item_id)
                if owner != from_id:
                    return False, "not_item_owner"
                if item_id not in from_p.inventory:
                    # repair if mapping says owner but inventory missing
                    from_p.inventory.add(item_id)
                from_p.inventory.discard(item_id)
                to_p.inventory.add(item_id)
                self.item_owner[item_id] = to_id
                return True, "ok"


STATE = GameState()


async def send(ws: WebSocketServerProtocol, msg: dict):
    try:
        await ws.send(jdump(msg))
    except Exception:
        pass


async def broadcast_to(players: Set[str], msg: dict):
    for pid in list(players):
        p = STATE.players.get(pid)
        if p:
            await send(p.ws, msg)


async def handle_message(ws: WebSocketServerProtocol, msg: dict):
    t = msg.get("type")
    if t == "hello":
        player_id = str(msg.get("player_id") or "")
        name = str(msg.get("name") or "")
        if not player_id:
            await send(ws, {"type": "error", "code": "missing_player_id"})
            return
        p = await STATE.register(ws, player_id, name or player_id)
        await send(ws, {"type": "hello_ok", "player_id": p.player_id, "name": p.name})
        inv = await STATE.snapshot_inventory(p.player_id)
        await send(ws, {"type": "inventory", **inv})
        return

    p = STATE.get_player_by_ws(ws)
    if not p:
        await send(ws, {"type": "error", "code": "not_authenticated"})
        return

    if t == "inventory_get":
        inv = await STATE.snapshot_inventory(p.player_id)
        await send(ws, {"type": "inventory", **inv})
        return

    if t == "item_spawn":
        # server-side economy would normally restrict this; left as admin/testing hook
        template = str(msg.get("template") or "")
        meta = msg.get("meta") or {}
        if not template:
            await send(ws, {"type": "error", "code": "missing_template"})
            return
        it = await STATE.create_item(p.player_id, template, meta if isinstance(meta, dict) else {})
        await send(ws, {"type": "item_spawn_ok", "item": {"item_id": it.item_id, "template": it.template, "meta": it.meta}})
        inv = await STATE.snapshot_inventory(p.player_id)
        await send(ws, {"type": "inventory", **inv})
        return

    if t == "trade_transfer":
        # client requests transfer of a single item to another player
        to_id = str(msg.get("to_player_id") or "")
        item_id = str(msg.get("item_id") or "")
        nonce = str(msg.get("nonce") or "")
        if not to_id or not item_id or not nonce:
            await send(ws, {"type": "trade_transfer_result", "ok": False, "code": "missing_fields", "nonce": nonce})
            return

        if not await STATE.ensure_nonce_once(p.player_id, nonce):
            await send(ws, {"type": "trade_transfer_result", "ok": False, "code": "duplicate_nonce", "nonce": nonce})
            return

        ok, code = await STATE.transfer_item(p.player_id, to_id, item_id)
        await send(ws, {"type": "trade_transfer_result", "ok": ok, "code": code, "nonce": nonce, "item_id": item_id, "to_player_id": to_id})

        if ok:
            # notify both parties with updated inventories (minimal correctness; can be optimized)
            inv_from = await STATE.snapshot_inventory(p.player_id)
            await send(ws, {"type": "inventory", **inv_from})
            to_p = STATE.players.get(to_id)
            if to_p:
                inv_to = await STATE.snapshot_inventory(to_id)
                await send(to_p.ws, {"type": "inventory", **inv_to})
                await send(to_p.ws, {"type": "trade_received", "from_player_id": p.player_id, "item_id": item_id})
        return

    await send(ws, {"type": "error", "code": "unknown_type", "got": t})


async def client_loop(ws: WebSocketServerProtocol):
    await send(ws, {"type": "welcome", "server_time_ms": now_ms()})
    try:
        async for raw in ws:
            try:
                msg = json.loads(raw)
                if not isinstance(msg, dict):
                    raise ValueError("not an object")
            except Exception:
                await send(ws, {"type": "error", "code": "bad_json"})
                continue
            await handle_message(ws, msg)
    finally:
        await STATE.unregister(ws)


async def main(host: str = "0.0.0.0", port: int = 8765):
    async with websockets.serve(
        client_loop,
        host,
        port,
        max_size=2 * 1024 * 1024,
        ping_interval=20,
        ping_timeout=20,
        close_timeout=5,
    ):
        logging.info("Server listening on %s:%d", host, port)
        await asyncio.Future()


